#include<bits/stdc++.h>
using namespace std;
long long n,m,a[5050],c[5050],x[5050];
long long dp[5050][5050],min1[5050][5050],ans;
int main()
{
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&a[i]);
    }
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&c[i]);
    }
    for(long long i=1;i<=m;i++)
    {
        scanf("%lld",&x[i]);
    }
    for(long long i=1;i<=n;i++)
    {
        min1[i][1]=c[i];
        for(long long j=2;j<=i;j++)
        {
            min1[i][j]=min(min1[i][j-1],c[i-j+1]);
        }
    }
    for(long long i=0;i<=n;i++)
    {
        for(long long j=1;j<=n;j++)
        {
            dp[i][j]=1e15;
        }
    }
    dp[0][0]=0;
    long long pos=1;
    for(long long i=1;i<=n;i++)
    {
        for(long long j=max(pos-1,1ll);j<=i;j++)
        {
            if(j!=pos-1)
            {
                dp[i][j]=min(dp[i][j],dp[i-1][j-1]+min1[i][j]+a[i]);
            }
            if(x[pos]!=i)
            {
                dp[i][j]=min(dp[i][j],dp[i-1][j]);
            }
        }
        if(i==x[pos])
        {
            pos++;
        }
    }
    ans=LLONG_MAX;
    for(long long i=m;i<=n;i++)
    {
        ans=min(ans,dp[n][i]);
    }
    printf("%lld",ans);
    return 0;
}
